app.post('/token', (req, res) => {
  const { grant_type, code, redirect_uri, client_id, client_secret } = req.body;
  
  if (grant_type !== 'authorization_code') {
    return res.status(400).json({ error: 'unsupported_grant_type' });
  }
  
  if (!code || !redirect_uri || !client_id || !client_secret) {
    return res.status(400).json({ error: 'invalid_request' });
  }
  
  const client = REGISTERED_CLIENTS.get(client_id);
  if (!client) {
    return res.status(401).json({ error: 'invalid_client' });
  }
  
  const clientSecretHash = hashPassword(client_secret);
  if (client.clientSecret !== clientSecretHash) {
    return res.status(401).json({ error: 'invalid_client' });
  }
  
  const codeData = authorizationCodes.get(code);
  
  if (!codeData) {
    return res.status(400).json({ error: 'invalid_grant' });
  }
  
  if (codeData.used) {
    authorizationCodes.delete(code);
    return res.status(400).json({ error: 'invalid_grant' });
  }
  
  if (Date.now() > codeData.expiresAt) {
    authorizationCodes.delete(code);
    return res.status(400).json({ error: 'invalid_grant' });
  }
  
  if (codeData.clientId !== client_id) {
    return res.status(400).json({ error: 'invalid_grant' });
  }
  
  if (codeData.redirectUri !== redirect_uri) {
    return res.status(400).json({ error: 'invalid_grant' });
  }
  
  codeData.used = true;
  
  const accessToken = generateSecureToken();
  const tokenData = {
    token: accessToken,
    username: codeData.username,
    clientId: client_id,
    expiresAt: Date.now() + TOKEN_EXPIRY
  };
  
  accessTokens.set(accessToken, tokenData);
  
  authorizationCodes.delete(code);
  
  res.json({
    access_token: accessToken,
    token_type: 'Bearer',
    expires_in: TOKEN_EXPIRY / 1000
  });
});

app.get('/userinfo', (req, res) => {
  const authHeader = req.headers.authorization;
  
  if (!authHeader || !authHeader.startsWith('Bearer ')) {
    return res.status(401).json({ error: 'invalid_token' });
  }
  
  const token = authHeader.substring(7);
  const tokenData = accessTokens.get(token);
  
  if (!tokenData) {
    return res.status(401).json({ error: 'invalid_token' });
  }
  
  if (Date.now() > tokenData.expiresAt) {
    accessTokens.delete(token);
    return res.status(401).json({ error: 'invalid_token' });
  }
  
  res.json({
    sub: tokenData.username,
    username: tokenData.username
  });
});

